const e=JSON.parse('{"key":"v-6f1e228c","path":"/pages/8143cc480faf9a11/","title":"new命令原理","lang":"zh-CN","frontmatter":{"title":"new命令原理","date":"2023-10-02T09:23:37.000Z","permalink":"/pages/8143cc480faf9a11","category":["前端","JavaScript文章"]},"headers":[],"git":{"createdTime":1698456390000,"updatedTime":1698456390000,"contributors":[{"name":"EvanSnowly","email":"2972561826@qq.com","commits":1}]},"readingTime":{"minutes":1.6,"words":480},"filePathRelative":"posts/javascirpt/02.new命令原理.md","localizedDate":"2023年10月2日","excerpt":"<h1> new命令原理</h1>\\n<p>使用new命令时，它后面的函数依次执行下面的步骤：</p>\\n<ol>\\n<li>创建一个空对象，作为将要返回的实例对象。</li>\\n<li>将这个空对象的原型，指向构造函数的prototype属性。</li>\\n<li>将这个空对象赋值给函数内部的this关键字。</li>\\n<li>开始执行构造函数内部的代码。</li>\\n<li>如果构造函数内有返回值且为对象类型，则返回该对象，否则返回上面创建的实例对象。</li>\\n</ol>\\n"}');export{e as data};
